package com.example.app

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private val prefs: SharedPreferences by lazy {
        getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            openHome()
            return
        }

        setContentView(R.layout.activity_main)

        val biometricButton: Button = findViewById(R.id.btnBiometric)
        val loginButton: Button = findViewById(R.id.btnLogin)
        val passwordInput: EditText = findViewById(R.id.etPassword)

        biometricButton.setOnClickListener {
            showBiometricPrompt()
        }

        loginButton.setOnClickListener {
            val password = passwordInput.text?.toString().orEmpty()
            if (validatePassword(password)) {
                markAuthenticated()
                openHome()
            } else {
                Toast.makeText(this, "Invalid password. Please try again.", Toast.LENGTH_SHORT).show()
            }
        }

        if (isBiometricAvailable()) {
            showBiometricPrompt()
        }
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        val result = biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK
        )
        return result == BiometricManager.BIOMETRIC_SUCCESS
    }

    private fun showBiometricPrompt() {
        if (!isBiometricAvailable()) {
            Toast.makeText(this, "Biometric authentication unavailable. Please use your password.", Toast.LENGTH_SHORT).show()
            return
        }

        val executor: Executor = ContextCompat.getMainExecutor(this)
        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Sign in")
            .setSubtitle("Use your fingerprint to continue")
            .setDescription("Authenticate to quickly access your account")
            .setNegativeButtonText("Use Password")
            .build()

        val biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    markAuthenticated()
                    openHome()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        this@MainActivity,
                        "Biometric authentication failed. Please use your password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@MainActivity,
                        "Fingerprint not recognized. Try again or use password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }
            }
        )

        biometricPrompt.authenticate(promptInfo)
    }

    private fun validatePassword(password: String): Boolean {
        return password == "1234"
    }

    private fun markAuthenticated() {
        prefs.edit().putBoolean(KEY_AUTHENTICATED, true).apply()
    }

    private fun openHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "authenticated"
    }
}

class HomeActivity : AppCompatActivity() {

    private val prefs: SharedPreferences by lazy {
        getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)

        if (!prefs.getBoolean("authenticated", false)) {
            startActivity(Intent(this, MainActivity::class.java))
            finish()
        }

        val logoutButton: Button = findViewById(R.id.btnLogout)
        logoutButton.setOnClickListener {
            prefs.edit().putBoolean("authenticated", false).apply()
            startActivity(Intent(this, MainActivity::class.java))
            finish()
        }
    }
}